		}

		// Run the script
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, fmt.Errorf("script execution error: %w", err)
		}

		// Convert the result to a boolean value
		booleanValue, err := value.ToBoolean()
		if err != nil {
